import java.util.Scanner;public class ExercicioSwitchCaseDiasUteis {    public static void main(String[] args) {        Scanner inputData = new Scanner(System.in);        System.out.println("Que dia estamos");        int data = inputData.nextInt();        switch (data){            case 1:                System.out.println("Hoje é domingo, não é um dia útil");                break;            case 2:                System.out.println("Hoje é segundo");                break;            case 3:                System.out.println("Hoje é terça");                break;            case 4:                System.out.println("Hoje é quarta");                break;            case 5:                System.out.println("Hoje é quinta");                break;            case 6:                System.out.println("Hojé é sexta");                break;            case 7:                System.out.println("Hoje é sabado, não é dia útil");                break;            default:                System.out.println("Dia não encontrado");                break;        }    }}